// Gather data from all parallel branches
const activityRaw = $('Fetch Agent Activity').first().json;
const workflowLogs = $('Fetch Workflow Logs').all().map(i => i.json).filter(i => i.workflow_name);
const errorSummary = $('Fetch Error Summary').all().map(i => i.json).filter(i => i.workflow_name);
const gmailStats = $('Fetch Gmail Stats').first().json;

// Parse activity log
const activityText = typeof activityRaw === 'string' ? activityRaw : (activityRaw.data || activityRaw.activity || JSON.stringify(activityRaw));
const activityLines = (typeof activityText === 'string' ? activityText : '').split('\n').filter(l => l.trim()).slice(0, 50);

const today = new Date().toISOString().split('T')[0];

let html = `<div style="font-family: Arial, sans-serif; max-width: 750px; margin: 0 auto;">`;
html += `<h1 style="color: #6200ea;">Daily Super Agent Report</h1>`;
html += `<p style="color: #666;">Report for: ${today}</p>`;

// Gmail Processing Stats
html += `<h2 style="color: #1a73e8;">Gmail Processing (24h)</h2>`;
html += `<table style="border-collapse: collapse; width: 100%;">`;
html += `<tr><td style="padding: 6px;">Total Processed</td><td style="padding: 6px; font-weight: bold;">${gmailStats.total_processed || 0}</td></tr>`;
html += `<tr><td style="padding: 6px;">Urgent</td><td style="padding: 6px; color: #d93025; font-weight: bold;">${gmailStats.urgent_count || 0}</td></tr>`;
html += `<tr><td style="padding: 6px;">Finance</td><td style="padding: 6px;">${gmailStats.finance_count || 0}</td></tr>`;
html += `<tr><td style="padding: 6px;">Newsletters</td><td style="padding: 6px;">${gmailStats.newsletter_count || 0}</td></tr>`;
html += `<tr><td style="padding: 6px;">Archived</td><td style="padding: 6px;">${gmailStats.archived_count || 0}</td></tr>`;
html += `<tr><td style="padding: 6px;">Drafts Created</td><td style="padding: 6px;">${gmailStats.drafts_count || 0}</td></tr>`;
html += `<tr><td style="padding: 6px;">Avg Priority</td><td style="padding: 6px;">${gmailStats.avg_priority || '-'}</td></tr>`;
html += `</table>`;

// Workflow Performance
if (workflowLogs.length > 0) {
  html += `<h2 style="color: #1a73e8;">Workflow Performance (24h)</h2>`;
  html += `<table style="border-collapse: collapse; width: 100%;">`;
  html += `<tr style="background: #f0f0f0;"><th style="padding: 6px; text-align: left;">Workflow</th><th style="padding: 6px;">Runs</th><th style="padding: 6px;">Status</th><th style="padding: 6px;">Avg Duration</th></tr>`;
  for (const w of workflowLogs) {
    const dur = w.avg_duration_sec ? Math.round(w.avg_duration_sec * 10) / 10 + 's' : '-';
    const statusColor = w.status === 'success' ? '#34a853' : '#d93025';
    html += `<tr><td style="padding: 6px; border-bottom: 1px solid #eee;">${w.workflow_name}</td><td style="padding: 6px; border-bottom: 1px solid #eee; text-align: center;">${w.run_count}</td><td style="padding: 6px; border-bottom: 1px solid #eee; text-align: center; color: ${statusColor};">${w.status}</td><td style="padding: 6px; border-bottom: 1px solid #eee; text-align: center;">${dur}</td></tr>`;
  }
  html += `</table>`;
}

// Errors
if (errorSummary.length > 0) {
  html += `<h2 style="color: #d93025;">Errors (24h)</h2>`;
  html += `<table style="border-collapse: collapse; width: 100%;">`;
  html += `<tr style="background: #fce8e6;"><th style="padding: 6px; text-align: left;">Workflow</th><th style="padding: 6px;">Count</th><th style="padding: 6px; text-align: left;">Sample Error</th></tr>`;
  for (const e of errorSummary) {
    html += `<tr><td style="padding: 6px; border-bottom: 1px solid #eee;">${e.workflow_name}</td><td style="padding: 6px; border-bottom: 1px solid #eee; text-align: center;">${e.error_count}</td><td style="padding: 6px; border-bottom: 1px solid #eee; font-size: 11px;">${(e.sample_error || '').substring(0, 100)}</td></tr>`;
  }
  html += `</table>`;
} else {
  html += `<h2 style="color: #34a853;">Errors: None in 24h</h2>`;
}

// Model Usage & Cost
try {
  const modelStats = $('Fetch Model Stats').first().json;
  if (modelStats && modelStats.interactions && modelStats.interactions.total_interactions > 0) {
    const inter = modelStats.interactions;
    html += `<h2 style="color: #1a73e8;">Model Usage (24h)</h2>`;
    html += `<table style="border-collapse: collapse; width: 100%;">`;
    html += `<tr style="background: #f0f0f0;"><th style="padding: 6px; text-align: left;">Model</th><th style="padding: 6px;">Requests</th><th style="padding: 6px;">%</th></tr>`;
    const dist = inter.model_distribution || {};
    const total = inter.total_interactions;
    for (const [model, count] of Object.entries(dist).sort((a,b) => b[1] - a[1])) {
      const pct = Math.round(count / total * 100);
      html += `<tr><td style="padding: 6px; border-bottom: 1px solid #eee;">${model}</td><td style="padding: 6px; border-bottom: 1px solid #eee; text-align: center;">${count}</td><td style="padding: 6px; border-bottom: 1px solid #eee; text-align: center;">${pct}%</td></tr>`;
    }
    html += `<tr style="font-weight: bold;"><td style="padding: 6px;">Total</td><td style="padding: 6px; text-align: center;">${total}</td><td style="padding: 6px; text-align: center;">—</td></tr>`;
    html += `</table>`;
    if (inter.error_count > 0) {
      html += `<p style="color: #d93025;">Error rate: ${inter.error_rate_pct}% (${inter.error_count} errors)</p>`;
    }
  }
  if (modelStats && modelStats.spend) {
    const spend = modelStats.spend;
    html += `<p><strong>API Spend:</strong> Today: $${(spend.today || 0).toFixed(2)} | Week: $${(spend.last_7_days || 0).toFixed(2)} | Month: $${(spend.last_30_days || 0).toFixed(2)}</p>`;
  }
} catch(e) { /* model stats not available */ }

// Agent Activity Highlights
html += `<h2 style="color: #1a73e8;">Agent Activity Log (last 50 lines)</h2>`;
html += `<pre style="background: #f5f5f5; padding: 12px; border-radius: 4px; font-size: 11px; overflow-x: auto; max-height: 400px;">`;
for (const line of activityLines) {
  html += line.replace(/</g, '&lt;').replace(/>/g, '&gt;') + '\n';
}
html += `</pre>`;

html += `<hr><p style="color: #999; font-size: 11px;">Daily Super Agent Report - Automated by n8n</p></div>`;

return [{ json: { report_html: html, report_date: today } }];
